/**
 * PID-based lock file for heartbeat single-instance enforcement.
 * Port of scripts/_lock_utils.py
 */

import {
  closeSync,
  constants,
  existsSync,
  mkdirSync,
  openSync,
  readFileSync,
  unlinkSync,
  writeSync,
} from 'node:fs'
import { homedir } from 'node:os'
import { dirname, resolve } from 'node:path'
import { execFileSync } from 'node:child_process'

// ---------------------------------------------------------------------------
// Path helpers
// ---------------------------------------------------------------------------

export function lockPath(): string {
  return resolve(homedir(), '.memorytree', 'heartbeat.lock')
}

// ---------------------------------------------------------------------------
// Lock acquisition
// ---------------------------------------------------------------------------

/**
 * Try to acquire the heartbeat lock. Returns `true` on success.
 *
 * If the lock file already exists, the stored PID is checked:
 * - alive process  -> return false (already running)
 * - dead process   -> reclaim the stale lock
 * - corrupt file   -> remove and retry
 *
 * Uses `O_CREAT | O_EXCL` to prevent TOCTOU races.
 */
export function acquireLock(): boolean {
  const path = lockPath()
  mkdirSync(dirname(path), { recursive: true })

  if (existsSync(path)) {
    let storedPid: number | undefined
    try {
      const raw = readFileSync(path, 'utf-8').trim()
      storedPid = parseInt(raw, 10)
      if (!Number.isFinite(storedPid)) {
        storedPid = undefined
      }
    } catch {
      // Corrupt lock file — treat as stale
      storedPid = undefined
    }

    if (storedPid === undefined) {
      // Corrupt or unreadable lock file — remove it
      removeLockFile(path)
    } else {
      if (isProcessAlive(storedPid)) {
        return false
      }
      // Stale lock from a dead process — reclaim
      removeLockFile(path)
    }
  }

  // Use exclusive create to prevent TOCTOU race
  try {
    const fd = openSync(path, constants.O_CREAT | constants.O_EXCL | constants.O_WRONLY)
    const pidBytes = Buffer.from(String(process.pid), 'utf-8')
    writeSync(fd, pidBytes)
    closeSync(fd)
  } catch {
    // Another process created the lock between our check and create,
    // or an OS-level I/O error occurred.
    return false
  }
  return true
}

// ---------------------------------------------------------------------------
// Lock release
// ---------------------------------------------------------------------------

/** Release the heartbeat lock. */
export function releaseLock(): void {
  removeLockFile(lockPath())
}

// ---------------------------------------------------------------------------
// Lock inspection
// ---------------------------------------------------------------------------

/** Read the PID from the lock file, or `null` if not locked / corrupt. */
export function readLockPid(): number | null {
  const path = lockPath()
  if (!existsSync(path)) {
    return null
  }
  try {
    const raw = readFileSync(path, 'utf-8').trim()
    const pid = parseInt(raw, 10)
    return Number.isFinite(pid) ? pid : null
  } catch {
    return null
  }
}

// ---------------------------------------------------------------------------
// Process liveness
// ---------------------------------------------------------------------------

/** Check whether a process with the given PID is still running. */
export function isProcessAlive(pid: number): boolean {
  if (pid <= 0) {
    return false
  }
  if (process.platform === 'win32') {
    return isProcessAliveWindows(pid)
  }
  return isProcessAliveUnix(pid)
}

function isProcessAliveUnix(pid: number): boolean {
  try {
    process.kill(pid, 0)
    return true
  } catch (err: unknown) {
    if (err instanceof Error && 'code' in err) {
      // EPERM means the process exists but we lack permission to signal it
      if ((err as NodeJS.ErrnoException).code === 'EPERM') {
        return true
      }
    }
    // ESRCH or any other error means the process does not exist
    return false
  }
}

function isProcessAliveWindows(pid: number): boolean {
  try {
    const output = execFileSync('tasklist', ['/FI', `PID eq ${pid}`, '/NH'], {
      encoding: 'utf-8',
      timeout: 5000,
      windowsHide: true,
    })
    // tasklist prints "INFO: No tasks are running..." when no match is found.
    // Use word-boundary regex to avoid substring false positives (e.g., PID 12 matching 312).
    return new RegExp(`\\b${pid}\\b`).test(output)
  } catch {
    return false
  }
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function removeLockFile(path: string): void {
  try {
    unlinkSync(path)
  } catch {
    // Ignore errors — file may already be gone
  }
}

/**
 * Logging setup for heartbeat — file output + stderr.
 * Port of scripts/_log_utils.py
 */

import { appendFileSync, mkdirSync } from 'node:fs'
import { homedir } from 'node:os'
import { resolve } from 'node:path'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type LogLevel = 'debug' | 'info' | 'warn' | 'error'

export interface Logger {
  debug(msg: string): void
  info(msg: string): void
  warn(msg: string): void
  error(msg: string): void
  exception(msg: string, err?: unknown): void
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const LEVEL_PRIORITY: Readonly<Record<LogLevel, number>> = {
  debug: 0,
  info: 1,
  warn: 2,
  error: 3,
}

const LEVEL_LABELS: Readonly<Record<LogLevel, string>> = {
  debug: 'DEBUG',
  info: 'INFO',
  warn: 'WARN',
  error: 'ERROR',
}

// ---------------------------------------------------------------------------
// Singleton
// ---------------------------------------------------------------------------

let singleton: MemoryTreeLogger | undefined

// ---------------------------------------------------------------------------
// MemoryTreeLogger
// ---------------------------------------------------------------------------

class MemoryTreeLogger implements Logger {
  private readonly levelPriority: number
  private readonly logFilePath: string | undefined

  constructor(logLevel: LogLevel) {
    this.levelPriority = LEVEL_PRIORITY[logLevel]

    const filePath = logFilePathForToday()
    const logDir = resolve(filePath, '..')
    try {
      mkdirSync(logDir, { recursive: true })
      // Verify we can write by doing nothing — the first real append will
      // confirm access.  We store the path only after the dir exists.
      this.logFilePath = filePath
    } catch {
      // Cannot create log directory — stderr-only mode.
      this.writeStderr('WARN', `Could not open log file: ${filePath}`)
      this.logFilePath = undefined
    }
  }

  debug(msg: string): void {
    this.log('debug', msg)
  }

  info(msg: string): void {
    this.log('info', msg)
  }

  warn(msg: string): void {
    this.log('warn', msg)
  }

  error(msg: string): void {
    this.log('error', msg)
  }

  exception(msg: string, err?: unknown): void {
    if (err instanceof Error && err.stack) {
      this.log('error', `${msg}\n${err.stack}`)
    } else if (err !== undefined) {
      this.log('error', `${msg}\n${String(err)}`)
    } else {
      this.log('error', msg)
    }
  }

  // -----------------------------------------------------------------------
  // Internal
  // -----------------------------------------------------------------------

  private log(level: LogLevel, msg: string): void {
    if (LEVEL_PRIORITY[level] < this.levelPriority) {
      return
    }

    const label = LEVEL_LABELS[level]
    const formatted = `${timestamp()} [${label}] ${msg}`

    this.writeStderr(label, msg)
    this.writeFile(formatted)
  }

  private writeStderr(_label: string, _msg: string): void {
    // Use the pre-formatted line for consistency.  We rebuild here so the
    // standalone warning in the constructor can also call this without a
    // full formatted line.
    const line = `${timestamp()} [${_label}] ${_msg}\n`
    process.stderr.write(line)
  }

  private writeFile(formatted: string): void {
    if (this.logFilePath === undefined) {
      return
    }
    try {
      appendFileSync(this.logFilePath, formatted + '\n', 'utf-8')
    } catch {
      // Silently ignore file-write errors — stderr is the primary channel.
    }
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Create (or return existing) singleton logger.
 *
 * The `logLevel` parameter is only used on the *first* call.  Subsequent
 * calls return the existing logger regardless of the level argument.
 */
export function setupLogging(logLevel: LogLevel = 'info'): Logger {
  if (singleton !== undefined) {
    return singleton
  }
  singleton = new MemoryTreeLogger(resolveLevel(logLevel))
  return singleton
}

/**
 * Return the singleton logger.  If `setupLogging` has not been called yet
 * the logger is auto-created with default settings (`info` level).
 */
export function getLogger(): Logger {
  if (singleton === undefined) {
    singleton = new MemoryTreeLogger(resolveLevel('info'))
  }
  return singleton
}

/**
 * Reset the singleton — primarily useful for tests.
 */
export function _resetLogger(): void {
  singleton = undefined
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function resolveLevel(level: string): LogLevel {
  const lower = level.toLowerCase()
  const mapping: Record<string, LogLevel> = {
    debug: 'debug',
    info: 'info',
    warn: 'warn',
    warning: 'warn',
    error: 'error',
  }
  return mapping[lower] ?? 'info'
}

function logFilePathForToday(): string {
  const today = new Date().toISOString().slice(0, 10) // YYYY-MM-DD in UTC
  return resolve(homedir(), '.memorytree', 'logs', `heartbeat-${today}.log`)
}

function timestamp(): string {
  // Produce YYYY-MM-DDTHH:MM:SS in UTC matching the Python datefmt.
  const now = new Date()
  const y = now.getUTCFullYear()
  const mo = String(now.getUTCMonth() + 1).padStart(2, '0')
  const d = String(now.getUTCDate()).padStart(2, '0')
  const h = String(now.getUTCHours()).padStart(2, '0')
  const mi = String(now.getUTCMinutes()).padStart(2, '0')
  const s = String(now.getUTCSeconds()).padStart(2, '0')
  return `${y}-${mo}-${d}T${h}:${mi}:${s}`
}

